    }

    for (int i = 0; i < rlc_bearer2release_list->list.count; i++) {
      // Validate LCID is within valid range
      if (*rlc_bearer2release_list->list.array[i] < 0 || *rlc_bearer2release_list->list.array[i] > MAX_LC_ID) {
        LOG_E(NR_MAC, "Invalid RLC bearer configuration: LCID %d is out of valid range [0, %d]\n",
              *rlc_bearer2release_list->list.array[i], MAX_LC_ID);
        continue;
      }

      for (int idx = 0; idx < sched_ctrl->dl_lc_num; idx++) {
        if (sched_ctrl->dl_lc_ids[idx] == *rlc_bearer2release_list->list.array[i]) {
          const int remaining_lcs = sched_ctrl->dl_lc_num - idx - 1;
          memmove(&sched_ctrl->dl_lc_ids[idx], &sched_ctrl->dl_lc_ids[idx + 1], sizeof(sched_ctrl->dl_lc_ids[idx]) * remaining_lcs);
          sched_ctrl->dl_lc_num--;
          break;
        }
      }
    }
  }

  // Validate RLC bearer to add list count and LCIDs
  if (rlc_bearer2add_list) {
    if (rlc_bearer2add_list->list.count > MAX_LC_NUM) {
      LOG_E(NR_MAC, "Invalid RLC bearer configuration: rlc_bearer2add_list count %d exceeds maximum %d\n",
            rlc_bearer2add_list->list.count, MAX_LC_NUM);
      return;
    }

    // keep lcids
    for (int i = 0; i < rlc_bearer2add_list->list.count; i++) {
      const int lcid = rlc_bearer2add_list->list.array[i]->logicalChannelIdentity;

      // Validate LCID is within valid range per 3GPP TS 38.331
      if (lcid < 0 || lcid > MAX_LC_ID) {
        LOG_E(NR_MAC, "Invalid RLC bearer configuration: LCID %d is out of valid range [0, %d]\n",
              lcid, MAX_LC_ID);
        continue;
      }

      // Verify we have capacity for new bearers
      if (sched_ctrl->dl_lc_num >= MAX_LC_NUM) {
        LOG_E(NR_MAC, "Invalid RLC bearer configuration: cannot add LCID %d, maximum number of logical channels (%d) already reached\n",
              lcid, MAX_LC_NUM);
        continue;
      }

      bool found = false;
      for (int idx = 0; idx < sched_ctrl->dl_lc_num; idx++) {
        if (sched_ctrl->dl_lc_ids[idx] == lcid) {
          found = true;
          break;
        }
      }

      if (!found) {
        sched_ctrl->dl_lc_num++;
        sched_ctrl->dl_lc_ids[sched_ctrl->dl_lc_num - 1] = lcid;
        LOG_D(NR_MAC, "Adding LCID %d (%s %d)\n", lcid, lcid < 4 ? "SRB" : "DRB", lcid);
      }
